const currentView = { x: 400, y: 300, phase: 1 };
const targetView = { x: 400, y: 300, phase: 1 };

const particles = [];
let tick = 0;

function getNode(id) {
  return nodes.find(n => n.id === id) || null;
}

function updatePhysics() {
  for (let i = 0; i < nodes.length; i++) {
